html:
{%- set no_default_print_heading = 1 -%}
{%- from "templates/print_formats/standard_macros.html" import add_header -%}

<div class="main-container">

  <style>
    html, body {
      margin:0;
      padding:0;
      font-family: Arial, sans-serif;
      font-size: 13px;
    }

    .main-container { padding: 8px; }

    .heading-label {
      font-size:20px;
      font-weight:700;
      text-align:center;
      margin-bottom:8px;
    }

    .section { margin-bottom:7px; }

    .section-title {
      font-size:14px;
      font-weight:600;
      border-bottom:1px solid #000;
      margin-bottom:2px;
    }

    .info-table,
    .cost-table,
    .items-table {
      width:100%;
      border-collapse:collapse;
    }

    .info-table td,
    .cost-table td {
      padding:2px 4px;
      font-size:13px;
    }

    .items-table th,
    .items-table td {
      padding:0 4px;
      font-size:13px;
    }

    .info-table,
    .cost-table {
      line-height:0.9;
    }

    .items-table tr {
      line-height:1.1;
    }

    .items-table th,
    .items-table .total-row {
      background:#f5f5f5;
      border-bottom:1px solid #ccc;
      color:#222;
      font-weight:700;
    }

    .rt { text-align:right; }
    .cn { text-align:center; }
    .bold { font-weight:600; }

    .job-description {
      line-height:1.4;
      padding:6px 4px;
      white-space:pre-wrap;
      word-wrap:break-word;
    }

    .job-description-section {
      margin-bottom:10px;
    }
  </style>

  <div class="heading-label">Quotation Cost Sheet</div>

  <!-- Header Info -->
  <div class="section">
    <table class="info-table">
      <tr>
        <td><strong>Quotation No.:</strong> {{ doc.name }}</td>
        <td class="rt"><strong>Date:</strong> {{ frappe.utils.formatdate(doc.transaction_date) }}</td>
      </tr>
      <tr>
        <td><strong>Customer:</strong> {{ doc.customer_name }}</td>
        <td class="rt"><strong>Job Type:</strong> {{ doc.job_type or "-" }}</td>
      </tr>
    </table>
  </div>

  <!-- Job Description -->
  <div class="section job-description-section">
    <div class="job-description">
      <strong>Job Description:</strong> {{ doc.job_description or "-" }}
    </div>
  </div>

  <!-- Cost & Revenue Summary -->
  <div class="section" style="margin-bottom:4px;">
    <div class="section-title">Cost & Revenue Summary</div>
    <table class="cost-table">
      <tr>
        <td>Expected Revenue</td>
        <td class="rt bold">
          {{ frappe.utils.fmt_money(doc.est_revenue or 0, currency=doc.currency) }}
        </td>
      </tr>
      <tr>
        <td>Expected Cost</td>
        <td class="rt bold">
          {{ frappe.utils.fmt_money(doc.est_cost or 0, currency=doc.currency) }}
        </td>
      </tr>
      <tr>
        <td>Expected Profit (Margin)</td>
        <td class="rt bold">
          {{ frappe.utils.fmt_money(
              doc.est_profit
              or ((doc.est_revenue or 0) - (doc.est_cost or 0)),
              currency=doc.currency
          ) }}
        </td>
      </tr>
      <tr>
        <td>Margin %</td>
        <td class="rt bold">
          {% if doc.est_revenue %}
            {{
              (
                (
                  doc.est_profit
                  or ((doc.est_revenue or 0) - (doc.est_cost or 0))
                ) / (doc.est_revenue or 1) * 100
              ) | round(2)
            }}%
          {% else %}
            0%
          {% endif %}
        </td>
      </tr>
    </table>
  </div>

  <!-- Item Breakdown -->
  <div class="section">
    <div class="section-title">Item Breakdown</div>
    <table class="items-table">
      <thead>
        <tr>
          <th style="width:30%">Description</th>
          <th style="width:20%">Supplier</th>
          <th class="rt" style="width:15%">Revenue</th>
          <th class="rt" style="width:15%">Cost</th>
          <th class="rt" style="width:15%">Margin</th>
        </tr>
      </thead>
      <tbody>
        {% for item in doc.items %}
        <tr>
          <td>{{ item.item_name }}</td>
          <td>{{ item.supplier or "-" }}</td>
          <td class="rt">
            {{ frappe.utils.fmt_money(item.amount or 0, currency=doc.currency) }}
          </td>
          <td class="rt">
            {{ frappe.utils.fmt_money(item.cost_amount or 0, currency=doc.currency) }}
          </td>
          <td class="rt">
            {{ frappe.utils.fmt_money(
                (item.amount or 0) - (item.cost_amount or 0),
                currency=doc.currency
            ) }}
          </td>
        </tr>
        {% endfor %}

        {% set total_revenue = doc.items | sum(attribute='amount') %}
        {% set total_cost = doc.items | sum(attribute='cost_amount') %}

        <tr class="total-row">
          <td class="bold" colspan="2">Total</td>
          <td class="rt bold">
            {{ frappe.utils.fmt_money(total_revenue or 0, currency=doc.currency) }}
          </td>
          <td class="rt bold">
            {{ frappe.utils.fmt_money(total_cost or 0, currency=doc.currency) }}
          </td>
          <td class="rt bold">
            {{ frappe.utils.fmt_money(
                (total_revenue or 0) - (total_cost or 0),
                currency=doc.currency
            ) }}
          </td>
        </tr>
      </tbody>
    </table>
  </div>

  <div style="margin-top:20px; font-size:12px; color:#888;">
    <em>For internal use only. Not for customer distribution.</em>
  </div>

</div>
